      && verifier.VerifyString(tablePos, 14 /*REQUESTER_PEER_ID*/, false)
      && verifier.VerifyString(tablePos, 16 /*REQUESTER_XPUB*/, false)
      && verifier.VerifyVectorOfData(tablePos, 18 /*REQUESTER_SIGNING_PUBKEY*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 20 /*REQUESTER_EPHEMERAL_PUBKEY*/, 1 /*byte*/, false)
      && verifier.VerifyString(tablePos, 22 /*REQUESTED_DOMAIN*/, false)
      && verifier.VerifyField(tablePos, 24 /*REQUESTED_TIMEOUT_MS*/, 8 /*ulong*/, 8, false)
      && verifier.VerifyField(tablePos, 26 /*REQUESTED_AT*/, 8 /*ulong*/, 8, false)
      && verifier.VerifyVectorOfData(tablePos, 28 /*CHALLENGE_NONCE*/, 1 /*byte*/, false)
      && verifier.VerifyField(tablePos, 30 /*EXPIRES_AT*/, 8 /*ulong*/, 8, false)
      && verifier.VerifyString(tablePos, 32 /*PROVIDER_PEER_ID*/, false)
      && verifier.VerifyString(tablePos, 34 /*ERROR_CODE*/, false)
      && verifier.VerifyString(tablePos, 36 /*ERROR_MESSAGE*/, false)
      && verifier.VerifyTableEnd(tablePos);
  }
}
